import{_ as l,o as a,c as e,a2 as o}from"./chunks/framework.QoSTM79V.js";const u=JSON.parse('{"title":"AI 编码红线","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/03-ai-coding-redlines.md","filePath":"mango-pmo/rules/03-ai-coding-redlines.md"}'),r={name:"mango-pmo/rules/03-ai-coding-redlines.md"};function t(n,i,d,c,s,_){return a(),e("div",null,[...i[0]||(i[0]=[o('<h1 id="ai-编码红线" tabindex="-1">AI 编码红线 <a class="header-anchor" href="#ai-编码红线" aria-label="Permalink to &quot;AI 编码红线&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><ul><li>适用于 Mango 框架开发者。</li><li>适用于基于 Mango 的业务项目开发者。</li><li>适用于 Agent、人工开发者和人机协同开发。</li><li>适用于后端、前端、数据库、测试、配置、脚本和文档交付。</li></ul><h2 id="_2-禁止事项" tabindex="-1">2. 禁止事项 <a class="header-anchor" href="#_2-禁止事项" aria-label="Permalink to &quot;2. 禁止事项&quot;">​</a></h2><ul><li>禁止写伪代码。</li><li>禁止写 TODO、FIXME、未来再优化、临时方案。</li><li>禁止在业务实现、接口返回、页面交互、持久化数据或交付数据中写 mock、fake、dummy、hardcode 内容作为最终交付。</li><li>测试中的 mock、stub、fake、spy 必须遵循对应测试规范，禁止替代被测目标或冒充真实链路验收。</li><li>禁止写空实现。</li><li>禁止用 <code>UnsupportedOperationException</code>、空方法、固定返回值或接口壳子冒充已实现。</li><li>禁止 catch 后吞异常。</li><li>禁止返回固定成功。</li><li>禁止绕过权限、租户、数据权限。</li><li>禁止未接数据库却伪装完成。</li><li>禁止未接真实接口却伪装完成。</li><li>禁止把应由数据库、配置、字典、枚举中心或真实接口提供的数据写死在 Controller、Service、前端页面或测试替身中。</li><li>禁止以“能编译、能启动、能打开页面”替代真实业务链路、真实数据、真实权限和真实交互验收。</li><li>禁止交付明显低质量页面，包括布局混乱、字段无业务分组、联动字段分散、按钮区域不统一、状态表达不清、加载/空/错误态缺失。</li></ul><h2 id="_3-必须满足" tabindex="-1">3. 必须满足 <a class="header-anchor" href="#_3-必须满足" aria-label="Permalink to &quot;3. 必须满足&quot;">​</a></h2><ul><li>代码必须可编译。</li><li>单测必须可运行。</li><li>配置必须可启动。</li><li>接口必须有真实实现。</li><li>异常必须有明确处理。</li><li>日志必须有上下文。</li><li>数据必须来自数据库、配置或真实接口。</li><li>页面必须完成真实交互、真实数据回显和 UI 布局走查。</li><li>字典、菜单、权限、租户默认数据、状态映射、业务配置等持久化或可运营数据必须有明确数据来源和初始化方式。</li><li>不确定时必须先列出阻塞点。</li></ul><h2 id="_4-交付要求" tabindex="-1">4. 交付要求 <a class="header-anchor" href="#_4-交付要求" aria-label="Permalink to &quot;4. 交付要求&quot;">​</a></h2><ul><li>交付报告必须说明实际验证命令和结果。</li><li>未连接真实数据库、真实接口或真实权限链路时，必须标记为阻塞或例外，禁止声明完成。</li><li>未完成真实 UI 走查、真实接口联调或真实数据来源确认时，必须标记为未验证，禁止声明页面或接口可用。</li><li>发现红线冲突时，必须先修复冲突；无法修复时，必须在交付台账中标记 <code>EXCEPTION</code> 并写明用户确认依据。</li></ul>',9)])])}const m=l(r,[["render",t]]);export{u as __pageData,m as default};
